// Get the raw text output from the AI agent.
const aiResponseText = $input.first().json.output;

// --- Step 1: Clean and Extract the JSON String ---
// AI models sometimes wrap their JSON in ```json ... ```. This line removes it.
const cleanedJsonString = aiResponseText.replace(/^```json\n/, '').replace(/\n```$/, '');

try {
  // --- Step 2: Parse the String into a JavaScript Object ---
  const assessmentData = JSON.parse(cleanedJsonString);

  // --- Step 3: Validate that Essential Top-Level Keys Exist ---
  const requiredFields = [
    'overall_assessment', 
    'detailed_scores', 
    'skill_gaps', 
    'strengths', 
    'recommendations', 
    'inline_feedback',
    'review_summary',
    'next_steps'
  ];

  // Find any fields from our required list that are missing in the AI's response.
  const missingFields = requiredFields.filter(field => !(field in assessmentData));

  if (missingFields.length > 0) {
    // If fields are missing, it's an invalid response.
    throw new Error(`AI response is missing required top-level keys: ${missingFields.join(', ')}`);
  }

  // --- Step 4: If everything is successful, output the validated data ---
  return [{
    json: {
      assessmentData: assessmentData, // The full, validated JSON object
      isValid: true,
      error: null
    }
  }];

} catch (error) {
  // --- Step 5: If JSON.parse fails or validation fails, output an error object ---
  return [{
    json: {
      assessmentData: null,
      isValid: false,
      error: error.message,
      rawResponse: aiResponseText // Include the original text for debugging
    }
  }];
}

