function base64url(input) {
  return Buffer.from(JSON.stringify(input))
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

const now = Math.floor(Date.now() / 1000);

const header = { alg: 'RS256', typ: 'JWT' };
const payload = {
  iat: now,
  exp: now + (10 * 60), // 10 minutes
  iss: appId,
};

const headerBase64 = base64url(header);
const payloadBase64 = base64url(payload);
const data = `${headerBase64}.${payloadBase64}`;

const signature = crypto
  .createSign('RSA-SHA256')
  .update(data)
  .sign(privateKey, 'base64')
  .replace(/=/g, '')
  .replace(/\+/g, '-')
  .replace(/\//g, '_');

const token = `${data}.${signature}`;

return [{ json: { jwt: token } }];

const { Buffer } = require('buffer');
const originalFile = $input.first();

try {
  const decodedContent = Buffer.from(originalFile.json.content, 'base64').toString('utf8');

  // Detect if it's JSON or code/text
  let analysisData;
  let fileType = 'unknown';

  try {
    // Try to parse as JSON first
    analysisData = JSON.parse(decodedContent);
    fileType = 'json';
  } catch (jsonError) {
    // If not JSON, treat as text/code
    analysisData = {
      content: decodedContent,
      filename: originalFile.json.name,
      isCode: true
    };
    fileType = 'text';
  }

  return [
    {
      json: {
        analysis: analysisData,
        originalFile: originalFile.json,
        fileType: fileType,
        success: true
      }
    }
  ];

} catch (error) {
  return [
    {
      json: {
        error: Error,
        success: false
      }
    }
  ];
}

// Get both inputs from the Merge node
const analysisInput = $input.all().find(item => item.json.analysis);
const prFiles = $input.all().filter(item => !item.json.analysis).map(item => item.json);

const analysisData = analysisInput ? analysisInput.json.analysis : null;
const fileType = analysisInput ? analysisInput.json.fileType : 'json';

// --- 1. BUILD THE REVIEW CONTEXT (Same as before) ---
let reviewContext = '';
if (fileType === 'json' && analysisData) {
  reviewContext += `**ORIGINAL ANALYSIS FOR: ${analysisData.filename}**\n- Score: ${analysisData.score}/100\n- Metrics: ${JSON.stringify(analysisData.metrics, null, 2)}\n- Summary: ${analysisData.summary}\n\n`;
} else if (analysisData) {
  reviewContext += `**REFERENCE INSTRUCTIONS FILE: ${analysisData.filename}**\n\`\`\`\n${analysisData.content}\n\`\`\`\n\n`;
}

reviewContext += `**PULL REQUEST SUBMISSION TO REVIEW:**\n`;

if (prFiles.length === 0) {
  reviewContext += "No files were changed in this pull request.";
} else {
  for (const file of prFiles) {
    let fileBlock = `### File: ${file.filename} [${file.status.toUpperCase()}]\n`;
    if (file.status === 'added' && file.content) {
      const safeContent = file.content.replace(/```/g, "''");
      const fileExtension = file.filename.split('.').pop() || 'text';
      fileBlock += "**Full content for new file:**\n";
      fileBlock += "```" + fileExtension + "\n" + safeContent + "\n```\n";
    } else if (file.patch) {
      const safePatch = file.patch.replace(/```/g, "''");
      fileBlock += "**Changes for modified file:**\n";
      fileBlock += "```diff\n" + safePatch + "\n```\n";
    } else {
      fileBlock += "_No reviewable content available._\n";
    }
    reviewContext += fileBlock + "\n---\n";
  }
}

// --- 2. BUILD THE FINAL STRUCTURED PROMPT FOR THE AI ---
const structuredPrompt = `You are an automated assessment agent for the NERD LMS system. Your task is to review the student's pull request submission based on the provided instructions and code. You MUST provide a comprehensive assessment in a specific JSON format.

**REVIEW CONTEXT:**
${reviewContext}

**YOUR MISSION:**
Analyze the student's submission and generate a detailed assessment that matches the NERD LMS database schema.

**REQUIRED OUTPUT FORMAT:**
You MUST respond with ONLY a valid JSON object in this exact structure. Do not include any text or markdown before or after the JSON block.

{
  "overall_assessment": {
    "score": 0,
    "grade": "F",
    "summary": "A brief, one-sentence summary of the student's performance."
  },
  "detailed_scores": {
    "technical_score": 0,
    "code_quality_score": 0,
    "problem_solving_score": 0,
    "documentation_score": 0,
    "testing_score": 0,
    "best_practices_score": 0
  },
  "skill_gaps": [
    {
      "skill": "Identified Skill Gap (e.g., Error Handling)",
      "gap_level": "moderate",
      "description": "A detailed description of why this is a skill gap.",
      "recommendation": "An actionable recommendation for the student."
    }
  ],
  "strengths": [
    {
      "skill": "Identified Strength (e.g., Code Structure)",
      "description": "A detailed description of what the student did well.",
      "evidence": "A reference to the specific part of the code that demonstrates this strength."
    }
  ],
  "recommendations": [
    {
      "type": "skill_gap",
      "priority": "medium",
      "title": "A short title for the recommendation (e.g., Improve Documentation)",
      "description": "A more detailed description of the recommended action.",
      "estimated_hours": 0,
      "resources": ["A list of generic resource topics, e.g., 'Code documentation best practices'"]
    }
  ],
  "inline_feedback": [
    {
      "file": "path/to/file.py",
      "line": 0,
      "comment": "A specific, line-level comment.",
      "type": "suggestion"
    }
  ],
  "review_summary": "A detailed, overall summary of the review, written in a constructive and encouraging tone for the student.",
  "next_steps": [
    "A list of clear, actionable next steps for the student."
  ]
}

**ASSESSMENT CRITERIA (Score 0-100 for each):**
- **Technical Score:** Correctness of logic, algorithm efficiency, use of frameworks.
- **Code Quality Score:** Readability, maintainability, adherence to style guides (PEP 8 for Python, etc.).
- **Problem Solving Score:** How effectively the submission meets the requirements from the INSTRUCTIONS.md file.
- **Documentation Score:** Quality of comments, README, and any other supporting documentation.
- **Testing Score:** (If applicable) Test coverage, quality, and effectiveness.
- **Best Practices Score:** Use of version control, security considerations, modern coding practices.

**GRADING SCALE:**
- A (90-100): Excellent
- B (80-89): Good
- C (70-79): Acceptable
- D (60-69): Needs Improvement
- F (0-59): Poor

**IMPORTANT:**
1. Provide realistic scores for ALL categories (0-100).
2. The entire output must be a single, valid JSON object.
3. Base your assessment on the student's submission compared against the reference instructions.

Now, review the PR and provide your assessment in the exact JSON format.`;


return [{
  json: {
    user_message: structuredPrompt
  }
}];
